var e=[{id:`L3_1`,type:`dialog`,speaker:`AGENT_EXTRA_NULL_NULL`,text:{KOREA:`그 많던 침식체를...... 전부 해치운 건가?`,JPN:`あれだけの侵食体どもを……すべて片づけたのか？`,ENG:`Did he really take care of all the C.O.s?`,TWN:`把這麼多的侵蝕體……全部解決掉了嗎？`},stage:{bg:`WAREHOUSE_01`,bgm:`BATTLE_VIRTUAL_2`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`AGENT_EXTRA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`AGENT_EXTRA_NULL_NULL`,text:{KOREA:`잠깐 눈이 부신 사이에 달려들던 침식체들이 비명조차 없이 사라지다니......`,JPN:`ちょっとまぶしいと思っていた間に、侵食体の群れが消滅するなんて……`,ENG:`A light flashed, and all the C.O.s disappeared without a trace.`,TWN:`只是一眨眼的功夫，湧來的侵蝕體連哀號都叫不出聲，竟然就這樣全部消失了……`},stage:{bg:`WAREHOUSE_01`,bgm:`BATTLE_VIRTUAL_2`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:{char_id:`AGENT_EXTRA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L5_1`,type:`dialog`,speaker:`AGENT_EXTRA_NULL_NULL`,text:{KOREA:`이거...... 어쩌면 정말로 살아 돌아갈 수도 있겠어.`,JPN:`これは……もしかしたら、本当に生きて帰れるかもしれないぞ。`,ENG:`Wow... Maybe we really have a chance to go back home alive.`,TWN:`這……說不定我們真的能活著回去。`},stage:{bg:`WAREHOUSE_01`,bgm:`BATTLE_VIRTUAL_2`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:{char_id:`AGENT_EXTRA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L7_1`,type:`dialog`,speaker:`KYLE_DELTA_NULL_NULL`,text:{KOREA:`대단하시군요, 소령님. 평소에도 이렇게 솔선수범하셨으면 좋았을 텐데요.`,JPN:`すごいですね、少佐。
普段からこんな風に率先してくだされば良かったものを。`,ENG:`Good job, Major. It's a shame, though, that it took this for you to perform so well.`,TWN:`了不起，少校大人。如果您平時也能這樣以身作則就好了。`},stage:{bg:`WAREHOUSE_01`,bgm:`BATTLE_VIRTUAL_2`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`KYLE_DELTA_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`SYLVIA_DELTA_NULL_NULL`,text:{KOREA:`뭐, 화력 하나는 인정해야겠네.`,JPN:`まあ、火力だけは認めなきゃだわ。`,ENG:`Well, you've got impressive firepower. At least I'll give you that.`,TWN:`是啦，火力這點我還是得認可的啦。`},stage:{bg:`WAREHOUSE_01`,bgm:`BATTLE_VIRTUAL_2`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SYLVIA_DELTA_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`SYLVIA_DELTA_NULL_NULL`,text:{KOREA:`하긴 힘이 센 만큼 머리가 나쁘니까 균형이 맞춰진 건가?`,JPN:`力が強い分頭が悪いからバランスがとれたというところかしら？`,ENG:`But then again, you're not as smart as you're strong, so that balances things out.`,TWN:`想來也是，畢竟力氣越大頭腦就越簡單，也算是互相平衡了吧？`},stage:{bg:`WAREHOUSE_01`,bgm:`BATTLE_VIRTUAL_2`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SYLVIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`JAKE_DELTA_NULL_NULL`,text:{KOREA:`하하, 실비아에게 칭찬을 듣다니 이거 영광인걸?`,JPN:`ハハ、シルビアに褒められるなんて光栄だな。`,ENG:`Hah hah. A compliment from Sylvia. This is a first.`,TWN:`哈哈，竟然能聽到希爾維亞稱讚我，這還真是榮幸啊？`},stage:{bg:`WAREHOUSE_01`,bgm:`BATTLE_VIRTUAL_2`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JAKE_DELTA_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`SYLVIA_DELTA_NULL_NULL`,text:{KOREA:`치, 칭찬한 거 아니거든?! 듣고 싶은 부분만 듣지 말라고!`,JPN:`べ、別に褒めたわけじゃないからね！？　勝手にフィルタリングしないでよ！　`,ENG:`Th-that wasn't a compliment! Do you have selective hearing?`,TWN:`才、才不是稱讚你好嗎？！別只聽自己想聽的部分啦！`},stage:{bg:`WAREHOUSE_01`,bgm:`BATTLE_VIRTUAL_2`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SYLVIA_DELTA_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`SYLVIA_DELTA_NULL_NULL`,text:{KOREA:`아무튼...... 다친 데는 없지?`,JPN:`とにかく……ケガはないよね？`,ENG:`Anyway... You're not hurt, are you?`,TWN:`總之……你沒有受傷吧？`},stage:{bg:`WAREHOUSE_01`,bgm:`BATTLE_VIRTUAL_2`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SYLVIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`JAKE_DELTA_NULL_NULL`,text:{KOREA:`그럼~ 고작 몸풀기인데 다쳤다간 체면이 안 서지.`,JPN:`もちろん。たかがウォーミングアップでケガなんかしたら、メンツ丸つぶれさ。`,ENG:`Nah. That was just warm-up, and if I got hurt from doing just that, then I'd have no business fighting here.`,TWN:`當然啦～只是活動一下筋骨而已，要是受傷不就太丟臉了。`},stage:{bg:`WAREHOUSE_01`,bgm:`BATTLE_VIRTUAL_2`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JAKE_DELTA_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`MARK_NPC_NULL_NULL`,text:{KOREA:`이봐! 제이크 소령! 전투 직후라 피곤하겠지만 조금 곤란한 일이 생겼어!`,JPN:`おい！　ジェイク少佐！
戦闘直後で疲れているだろうが、ちょっと困ったことが起きた！　`,ENG:`Hey, Major Walker! I know you just finished fighting, but we've got a problem.`,TWN:`喂！傑克少校！雖然你戰鬥後應該很累，但發生了一些麻煩事！`},stage:{bg:`WAREHOUSE_01`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MARK_NPC_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}},sfx:`FX_CUTSCEN_NOISE`},{id:`L16_1`,type:`dialog`,speaker:`MARK_NPC_NULL_NULL`,text:{KOREA:`이야기를 나눴으면 하는데......!`,JPN:`少し話せるか……！`,ENG:`Can we talk?`,TWN:`我想和你談談！`},stage:{bg:`WAREHOUSE_01`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MARK_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};